#!/usr/bin/env node
/**
 * check-3k-docs-drift.mjs
 *
 * Detects drift between docs/ (and src/) and two kinds of references that
 * point at them from the 3k-docs/ side:
 *
 *   1. Content-reuse imports inside 3k-docs/ wrapper pages, e.g.
 *      `import Ci from '@site/docs/continuous-integration/foo.md';`
 *   2. Doc-ID and folder references inside sidebars-3k-docs.ts, e.g.
 *      `id: 'platform/getting-started/index'` or
 *      `dirName: 'code-repository/config-repos'` — these are 3k-docs' own
 *      version of the manual/autogenerated sidebar systems already documented
 *      for sidebars.ts in CLAUDE.md's "Sidebar Navigation Configuration".
 *   3. Content-parity reminders (non-blocking) for modules listed as
 *      "rewritten" in 3k-docs-module-status.json — these modules no longer
 *      mirror docs/ via import, they carry their own hand-authored copy. If a
 *      docs/<module>/X.md changes in this diff and 3k-docs/<module>/X.md
 *      exists but wasn't touched in the same diff, this is surfaced as a
 *      reminder to confirm whether the rewritten copy also needs the update.
 *      Divergence is the intended design for these modules, so this never
 *      fails the build — it is a nudge, not drift.
 *
 * Background: 3k-docs/ pages don't contain real content — they import and render
 * a component from docs/ (see convert-3k-docs.mjs, which generates that pattern).
 * When a docs/ page is moved or renamed, any 3k-docs/ file importing its old path
 * breaks with a `@site/...` module-not-found error at `yarn build` time. That's
 * exactly what happened in the HDH-561 incident (2026-07-08 / 2026-07-16): the
 * build failed with ~22 stale import errors, and the failure surfaced *after*
 * merge, breaking every subsequent preview build until a human traced each one
 * down by hand. Moving a 3k-docs/ file itself (to keep it mirrored with a moved
 * docs/ file) can independently break sidebars-3k-docs.ts the same way moving a
 * file under docs/ can break sidebars.ts.
 *
 * This script:
 *   1. Uses git's rename detection to find docs/, src/, or 3k-docs/ files that
 *      were moved or renamed between two refs (default: HEAD^1 vs HEAD, matching
 *      the existing kebab-case Check step's convention).
 *   2. Scans every 3k-docs/*.md(x) file for `@site/docs/...` and `@site/src/...`
 *      imports, and scans sidebars-3k-docs.ts for `id:` and `dirName:` values,
 *      checking whether each still resolves to something on disk.
 *   3. If a broken reference matches a detected rename 1:1, that's a "safe" fix —
 *      rewrite it to the new path. Pass --fix to apply it. (Folder-level `dirName`
 *      renames are detected but not auto-fixed — inferring a directory rename
 *      from individual file renames is ambiguous enough that it's left to a human.)
 *   4. If a broken reference doesn't match a clean rename (e.g. the source was
 *      deleted, split, merged, or restructured — the CCM/legacy-prefix and
 *      HsuCalculator cases from the incident), that's reported as a failure
 *      requiring a human to update it manually.
 *
 * Usage:
 *   node scripts/check-3k-docs-drift.mjs            # check only, exit 1 on any drift
 *   node scripts/check-3k-docs-drift.mjs --fix       # apply safe fixes, still exit 1
 *                                                     # if unresolved drift remains
 *
 * Env overrides (for local testing outside CI):
 *   DRIFT_BASE_REF, DRIFT_HEAD_REF   (default: HEAD^1, HEAD)
 *
 * Content-parity reminders (see 3k-docs-module-status.json) are written to
 * .3k-docs-parity-warnings.txt when present, so a CI step can surface them
 * distinctly from hard failures without re-parsing stdout. This file is
 * removed automatically when there is nothing to flag.
 */

import { execSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";

const REPO_ROOT = process.cwd();
const REUSE_DIR = "3k-docs";
const SIDEBAR_FILE = "sidebars-3k-docs.ts";
const MODULE_STATUS_FILE = "3k-docs-module-status.json";
const PARITY_MARKER_FILE = ".3k-docs-parity-warnings.txt";
const IMPORT_RE =
  /import\s+([A-Za-z_$][\w$]*)\s+from\s+['"]@site\/(docs|src)\/([^'"]+)['"]\s*;?/g;
// Narrower than IMPORT_RE on purpose: only @site/docs/... imports indicate the
// page's *content* is still reused from docs/ (a true wrapper). @site/src/...
// imports are shared components (Tabs, Troubleshoot, FAQ) that rewritten pages
// with real hand-authored content routinely use too.
const WRAPPER_IMPORT_RE =
  /import\s+[A-Za-z_$][\w$]*\s+from\s+['"]@site\/docs\/[^'"]+['"]/;
const SIDEBAR_ID_RE = /\bid:\s*(['"])((?:(?!\1).)+)\1/g;
const SIDEBAR_DIRNAME_RE = /\bdirName:\s*(['"])((?:(?!\1).)+)\1/g;

const APPLY_FIX = process.argv.includes("--fix");

function sh(cmd) {
  return execSync(cmd, { cwd: REPO_ROOT, encoding: "utf8" }).trim();
}

function resolveBaseHead() {
  const base = process.env.DRIFT_BASE_REF || "HEAD^1";
  const head = process.env.DRIFT_HEAD_REF || "HEAD";
  try {
    sh(`git rev-parse ${base}`);
    return { base, head };
  } catch {
    console.warn(
      `⚠️  Could not resolve ${base} (shallow clone or single-commit branch?). ` +
        `Falling back to comparing against origin/main. Rename-based auto-fix ` +
        `may be less precise; broken-import detection still runs in full.`
    );
    try {
      sh("git rev-parse origin/main");
      return { base: "origin/main", head };
    } catch {
      return { base: null, head };
    }
  }
}

// docs/ and src/ cover content-reuse import targets; 3k-docs/ is included too
// so renames of the wrapper files themselves (which sidebars-3k-docs.ts
// references by id/dirName) are tracked.
const WATCHED_PATHS = "docs/ src/ 3k-docs/";

function getRenames(base, head) {
  if (!base) return [];
  let out = "";
  try {
    out = sh(`git diff --name-status -M50% ${base} ${head} -- ${WATCHED_PATHS}`);
  } catch {
    return [];
  }
  const renames = [];
  for (const line of out.split("\n").filter(Boolean)) {
    const parts = line.split("\t");
    if (parts[0].startsWith("R")) {
      renames.push({ from: parts[1], to: parts[2] });
    }
  }
  return renames;
}

function getPureDeletions(base, head) {
  if (!base) return new Set();
  let out = "";
  try {
    out = sh(
      `git diff --name-status -M50% --diff-filter=D ${base} ${head} -- ${WATCHED_PATHS}`
    );
  } catch {
    return new Set();
  }
  return new Set(
    out
      .split("\n")
      .filter(Boolean)
      .map((l) => l.split("\t")[1])
  );
}

// 3k-docs-module-status.json is the single source of truth for which
// top-level modules are being (or have been) cut over from the wrapper-import
// pattern to hand-authored content. Its "rewritten" array drives the parity
// nudge below -- a module can be listed here while only partially rewritten,
// since findContentParityWarnings() checks each file's own content, not just
// module membership.
function loadRewrittenModules() {
  const p = path.join(REPO_ROOT, MODULE_STATUS_FILE);
  if (!fs.existsSync(p)) return [];
  try {
    const data = JSON.parse(fs.readFileSync(p, "utf8"));
    return Array.isArray(data.rewritten) ? data.rewritten : [];
  } catch {
    console.warn(`⚠️  Could not parse ${MODULE_STATUS_FILE}; skipping content-parity check.`);
    return [];
  }
}

function getChangedFiles(base, head, prefix) {
  if (!base) return new Set();
  let out = "";
  try {
    out = sh(`git diff --name-only ${base} ${head} -- ${prefix}`);
  } catch {
    return new Set();
  }
  return new Set(out.split("\n").filter(Boolean));
}

// Non-blocking: for each "rewritten" module, if a docs/ file changed in this
// diff and its 3k-docs/ counterpart has already been rewritten with real
// content (no @site/... import left) but wasn't touched in the same diff,
// remind a human to confirm whether the hand-authored copy needs the same
// update. Never contributes to the exit code -- these files are expected to
// diverge from docs/ by design, this just flags the moment a change *might*
// be relevant to both.
//
// "rewritten" modules can be a mix of already-rewritten and still-wrapper
// files (a module-level cutover happens page by page, e.g. platform is
// partway through). A companion file that still contains an @site/... import
// is skipped here on purpose: it stays in sync with docs/ automatically via
// that import, so a docs/-only content edit needs no parallel 3k-docs change,
// and flagging it would just be noise.
function findContentParityWarnings(base, head, rewrittenModules) {
  if (!base || rewrittenModules.length === 0) return [];
  const warnings = [];
  for (const mod of rewrittenModules) {
    const changedDocs = getChangedFiles(base, head, `docs/${mod}/`);
    const changed3k = getChangedFiles(base, head, `${REUSE_DIR}/${mod}/`);
    for (const docFile of changedDocs) {
      const rest = docFile.slice(`docs/${mod}/`.length);
      const companion = `${REUSE_DIR}/${mod}/${rest}`;
      const resolved = resolveExistingFile(companion);
      if (!resolved) continue;
      if (changed3k.has(companion) || changed3k.has(resolved)) continue;

      const companionContent = fs.readFileSync(path.join(REPO_ROOT, resolved), "utf8");
      // Only an @site/docs/... import means the page's body is still reused
      // from docs/ (a true wrapper). Rewritten pages routinely import shared
      // components from @site/src/... (Tabs, Troubleshoot, FAQ) while holding
      // real hand-authored content -- matching IMPORT_RE (which also accepts
      // @site/src/...) here would misclassify those as wrappers and silently
      // skip the parity reminder on exactly the pages it's meant to catch.
      if (WRAPPER_IMPORT_RE.test(companionContent)) continue; // still a docs/-backed wrapper, auto-synced

      warnings.push({ docFile, companion: resolved });
    }
  }
  return warnings;
}

function walk(dir, list = []) {
  if (!fs.existsSync(dir)) return list;
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) walk(full, list);
    else if (entry.name.endsWith(".md") || entry.name.endsWith(".mdx"))
      list.push(full);
  }
  return list;
}

function findImports() {
  const files = walk(REUSE_DIR);
  const results = [];
  for (const file of files) {
    const content = fs.readFileSync(file, "utf8");
    let match;
    IMPORT_RE.lastIndex = 0;
    while ((match = IMPORT_RE.exec(content))) {
      const [matchText, , base, relPath] = match;
      results.push({
        file,
        importedPath: `${base}/${relPath}`,
        matchText,
      });
    }
  }
  return results;
}

// Component imports (e.g. `@site/src/components/Docs/Foo`) are extensionless
// and resolved by webpack/TS module resolution, not a literal file. Mirror
// that resolution: exact path, then common extensions, then dir/index.*.
const RESOLVABLE_EXTS = ["", ".md", ".mdx", ".tsx", ".ts", ".jsx", ".js"];

function exists(relPath) {
  const abs = path.join(REPO_ROOT, relPath);

  for (const ext of RESOLVABLE_EXTS) {
    if (fs.existsSync(abs + ext) && fs.statSync(abs + ext).isFile()) return true;
  }

  if (fs.existsSync(abs) && fs.statSync(abs).isDirectory()) {
    for (const ext of RESOLVABLE_EXTS.filter((e) => e)) {
      if (fs.existsSync(path.join(abs, "index" + ext))) return true;
    }
  }

  return false;
}

// Like exists(), but returns the actual on-disk relative path (with whatever
// extension resolved) instead of a boolean -- needed so the parity check can
// read the resolved file's own content.
function resolveExistingFile(relPath) {
  const abs = path.join(REPO_ROOT, relPath);
  for (const ext of RESOLVABLE_EXTS) {
    if (fs.existsSync(abs + ext) && fs.statSync(abs + ext).isFile()) {
      return relPath + ext;
    }
  }
  return null;
}

// Resolve a possibly-extensionless import path against the rename map. Git
// reports renames with real (extensioned) paths, e.g. `src/.../Foo.tsx`, but
// a component import may reference `src/.../Foo` with no extension — try both.
function resolveRename(renameMap, importedPath) {
  for (const candidate of [
    importedPath,
    ...RESOLVABLE_EXTS.filter((e) => e).map((ext) => importedPath + ext),
  ]) {
    if (renameMap.has(candidate)) {
      let to = renameMap.get(candidate);
      // Preserve the original extensionless style if that's how it was imported.
      if (candidate !== importedPath) {
        to = to.replace(/\.(tsx|ts|jsx|js|mdx|md)$/, "");
      }
      return to;
    }
  }
  return null;
}

// Same extension-tolerant matching for the pure-deletions set.
function wasDeleted(deletions, importedPath) {
  return [
    importedPath,
    ...RESOLVABLE_EXTS.filter((e) => e).map((ext) => importedPath + ext),
  ].some((c) => deletions.has(c));
}

function dirExists(relPath) {
  const abs = path.join(REPO_ROOT, relPath);
  return fs.existsSync(abs) && fs.statSync(abs).isDirectory();
}

// sidebars-3k-docs.ts has large blocks of commented-out sidebar config (old
// modules kept for reference). Blank those out before matching so `id:`/
// `dirName:` inside `//` or `/* */` comments don't get flagged as live drift --
// replace with same-length whitespace (preserving newlines) so match offsets
// still line up 1:1 with the real file for the later matchText-based replace.
function stripComments(content) {
  return content.replace(/\/\*[\s\S]*?\*\/|\/\/.*$/gm, (m) =>
    m.replace(/[^\n]/g, " ")
  );
}

// sidebars-3k-docs.ts is a single TS file, not a Docusaurus content tree, so
// we scan it with regexes rather than trying to parse it as an AST -- same
// pragmatic approach the existing find-broken-frontmatter.mjs / lint-3k-docs.mjs
// scripts already use for 3k-docs/ content.
function findSidebarRefs() {
  if (!fs.existsSync(path.join(REPO_ROOT, SIDEBAR_FILE))) {
    return { ids: [], dirNames: [] };
  }
  const raw = fs.readFileSync(path.join(REPO_ROOT, SIDEBAR_FILE), "utf8");
  const content = stripComments(raw);

  const ids = [];
  SIDEBAR_ID_RE.lastIndex = 0;
  let m;
  while ((m = SIDEBAR_ID_RE.exec(content))) {
    const [matchText, quote, value] = m;
    ids.push({ value, matchText, quote });
  }

  const dirNames = [];
  SIDEBAR_DIRNAME_RE.lastIndex = 0;
  while ((m = SIDEBAR_DIRNAME_RE.exec(content))) {
    const [matchText, quote, value] = m;
    dirNames.push({ value, matchText, quote });
  }

  return { ids, dirNames };
}

function main() {
  const { base, head } = resolveBaseHead();
  const renameMap = new Map(getRenames(base, head).map((r) => [r.from, r.to]));
  const deletions = getPureDeletions(base, head);

  const imports = findImports();
  const byFile = new Map();
  for (const imp of imports) {
    if (!byFile.has(imp.file)) byFile.set(imp.file, []);
    byFile.get(imp.file).push(imp);
  }

  const fixed = [];
  const broken = [];

  for (const [file, fileImports] of byFile) {
    let content = fs.readFileSync(file, "utf8");
    let changed = false;

    for (const imp of fileImports) {
      if (exists(imp.importedPath)) continue;

      const newPath = resolveRename(renameMap, imp.importedPath);
      if (newPath) {
        if (APPLY_FIX) {
          const newImportStmt = imp.matchText.replace(
            `@site/${imp.importedPath}`,
            `@site/${newPath}`
          );
          content = content.split(imp.matchText).join(newImportStmt);
          changed = true;
        }
        fixed.push({
          kind: "import",
          file,
          from: imp.importedPath,
          to: newPath,
          applied: APPLY_FIX,
        });
      } else {
        broken.push({
          kind: "import",
          file,
          importedPath: imp.importedPath,
          reason: wasDeleted(deletions, imp.importedPath)
            ? "source file was deleted/restructured in this diff (not a simple rename) — needs a manual repoint"
            : "source file does not exist on disk (pre-existing drift, or moved outside this diff's range)",
        });
      }
    }

    if (changed) fs.writeFileSync(file, content);
  }

  // --- sidebars-3k-docs.ts: id: entries (manual doc-ID sidebar system) ---
  const { ids, dirNames } = findSidebarRefs();
  const brokenDirs = [];

  if (ids.length || dirNames.length) {
    const sidebarPath = path.join(REPO_ROOT, SIDEBAR_FILE);
    let sidebarContent = fs.readFileSync(sidebarPath, "utf8");
    let sidebarChanged = false;

    for (const { value, matchText, quote } of ids) {
      const importedPath = `${REUSE_DIR}/${value}`;
      if (exists(importedPath)) continue;

      const newPath = resolveRename(renameMap, importedPath);
      if (newPath) {
        const newId = newPath.slice(REUSE_DIR.length + 1);
        if (APPLY_FIX) {
          const newMatchText = matchText.replace(
            `${quote}${value}${quote}`,
            `${quote}${newId}${quote}`
          );
          sidebarContent = sidebarContent.split(matchText).join(newMatchText);
          sidebarChanged = true;
        }
        fixed.push({
          kind: "sidebar-id",
          file: SIDEBAR_FILE,
          from: `id: '${value}'`,
          to: `id: '${newId}'`,
          applied: APPLY_FIX,
        });
      } else {
        broken.push({
          kind: "sidebar-id",
          file: SIDEBAR_FILE,
          importedPath: `id: '${value}' (-> ${importedPath})`,
          reason: wasDeleted(deletions, importedPath)
            ? "the 3k-docs file this id points to was deleted/restructured in this diff — needs a manual sidebar update"
            : "the 3k-docs file this id points to does not exist on disk (pre-existing drift, or moved outside this diff's range)",
        });
      }
    }

    // dirName: entries (autogenerated-category sidebar system). Detected but
    // not auto-fixed: inferring a folder rename from individual file renames
    // is ambiguous, so this always needs a human to confirm the new dirName.
    for (const { value } of dirNames) {
      const importedPath = `${REUSE_DIR}/${value}`;
      if (dirExists(importedPath)) continue;
      brokenDirs.push({ file: SIDEBAR_FILE, dirName: value, importedPath });
    }

    if (sidebarChanged) fs.writeFileSync(sidebarPath, sidebarContent);
  }

  const importFixed = fixed.filter((f) => f.kind === "import");
  const sidebarFixed = fixed.filter((f) => f.kind === "sidebar-id");
  const importBroken = broken.filter((b) => b.kind === "import");
  const sidebarBroken = broken.filter((b) => b.kind === "sidebar-id");

  if (importFixed.length) {
    console.log(
      `\n${APPLY_FIX ? "✅ Auto-fixed" : "🔧 Auto-fixable"} ${importFixed.length} content-reuse import path(s):`
    );
    for (const f of importFixed) {
      console.log(
        `  - ${f.file}\n      @site/${f.from}  ->  @site/${f.to}${
          f.applied ? "" : "   (run with --fix to apply)"
        }`
      );
    }
  }

  if (sidebarFixed.length) {
    console.log(
      `\n${APPLY_FIX ? "✅ Auto-fixed" : "🔧 Auto-fixable"} ${sidebarFixed.length} ${SIDEBAR_FILE} entry(ies):`
    );
    for (const f of sidebarFixed) {
      console.log(
        `  - ${f.file}\n      ${f.from}  ->  ${f.to}${
          f.applied ? "" : "   (run with --fix to apply)"
        }`
      );
    }
  }

  if (importBroken.length) {
    console.log(
      `\n❌ ${importBroken.length} broken content-reuse import(s) need manual attention:`
    );
    for (const b of importBroken) {
      console.log(
        `  - ${b.file}\n      imports @site/${b.importedPath}\n      ${b.reason}`
      );
    }
    console.log(
      `\nThese don't have an unambiguous rename mapping (content may have been split, ` +
        `merged, or moved to a differently-named path — see the CCM legacy/ and ` +
        `HsuCalculator cases from the 2026-07-16 incident). Update the import in the ` +
        `3k-docs file(s) above to point at the correct docs/ source, or regenerate the ` +
        `wrapper with 'node scripts/convert-3k-docs.mjs <module> <Component>'.`
    );
  }

  if (sidebarBroken.length) {
    console.log(
      `\n❌ ${sidebarBroken.length} broken ${SIDEBAR_FILE} entry(ies) need manual attention:`
    );
    for (const b of sidebarBroken) {
      console.log(`  - ${b.file}\n      ${b.importedPath}\n      ${b.reason}`);
    }
  }

  if (brokenDirs.length) {
    console.log(
      `\n❌ ${brokenDirs.length} broken dirName entry(ies) in ${SIDEBAR_FILE} (not auto-fixable):`
    );
    for (const d of brokenDirs) {
      console.log(
        `  - ${d.file}\n      dirName: '${d.dirName}' (-> ${d.importedPath})\n      ` +
          `this folder does not exist on disk — if it was renamed or moved, update dirName ` +
          `to the new folder path by hand (folder renames are not auto-fixed).`
      );
    }
  }

  if (
    !fixed.length &&
    !broken.length &&
    !brokenDirs.length
  ) {
    console.log("✅ No 3k-docs content-reuse or sidebar drift detected.");
  }

  // --- content-parity reminder for "rewritten" modules (non-blocking) ---
  const rewrittenModules = loadRewrittenModules();
  const parityWarnings = findContentParityWarnings(base, head, rewrittenModules);
  const markerPath = path.join(REPO_ROOT, PARITY_MARKER_FILE);

  if (parityWarnings.length) {
    console.log(
      `\n💡 ${parityWarnings.length} content-parity reminder(s) (non-blocking):`
    );
    for (const w of parityWarnings) {
      console.log(
        `  - ${w.docFile} changed, but ${w.companion} (its hand-authored 3k-docs\n` +
          `      copy) was not touched in this diff. Confirm whether the rewritten\n` +
          `      copy also needs this update -- these modules diverge by design, so\n` +
          `      this is a reminder, not an error.`
      );
    }
    fs.writeFileSync(
      markerPath,
      parityWarnings.map((w) => `${w.docFile} -> ${w.companion}`).join("\n") + "\n"
    );
  } else if (fs.existsSync(markerPath)) {
    // Best-effort cleanup of a marker left by a prior run. Never let this
    // crash the check -- a permission quirk on some filesystem/mount is not
    // a reason to fail a build over a stale reminder file.
    try {
      fs.unlinkSync(markerPath);
    } catch {
      fs.writeFileSync(markerPath, "");
    }
  }

  if (broken.length > 0 || brokenDirs.length > 0) process.exit(1);
  if (fixed.length > 0 && !APPLY_FIX) process.exit(1);
  process.exit(0);
}

main();
